import { useState, useEffect, useCallback } from 'react';
import reportService from '../services/reportService';

export const useDashboard = (year, month) => {
  const [summary, setSummary] = useState(null);
  const [deptStats, setDeptStats] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetch = useCallback(async () => {
    try {
      setLoading(true);
      const [summaryRes, deptRes] = await Promise.all([
        reportService.getSummary(year, month),
        reportService.getDepartments(),
      ]);
      setSummary(summaryRes.data.data.summary);
      setDeptStats(deptRes.data.data.stats);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [year, month]);

  useEffect(() => { fetch(); }, [fetch]);
  return { summary, deptStats, loading, error, refresh: fetch };
};
